namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new NotificationItem { Id = _nextId++, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-2) },
        });
    }

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > lastSeenId)
                                      .OrderByDescending(n => n.Timestamp)
                                      .ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Call this periodically or on a timer to generate fake activity.
    /// </summary>
    public Task SimulateNewNotificationAsync()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Scheduled maintenance tonight at 11 PM.",
            "Your export is ready to download.",
            "A teammate commented on your PR.",
            "Server deployment completed successfully.",
        };

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new NotificationItem
            {
                Id = _nextId++,
                Message = msg,
                Timestamp = DateTime.UtcNow,
            });
        }

        return Task.CompletedTask;
    }
}

