@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationSvc
@inject PersistentComponentState ApplicationState
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var item in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@item.Message</div>
                <small class="text-muted">@item.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationItem> notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        // Try to restore state persisted during prerender
        _persistSub = ApplicationState.RegisterOnPersisting(PersistState);

        if (ApplicationState.TryTakeFromJson<List<NotificationItem>>("notifications", out var restored))
        {
            // Interactive render: reuse the prerendered data — no second fetch
            notifications = restored!;
        }
        else
        {
            // Prerender: load from service (this data will appear in the initial HTML)
            notifications = await NotificationSvc.GetNotificationsAsync();
        }
    }

    private Task PersistState()
    {
        ApplicationState.PersistAsJson("notifications", notifications);
        return Task.CompletedTask;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during static prerender,
            // so this is safe — polling starts only when truly interactive.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        var lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;

        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                // Simulate a new notification arriving on the server
                await NotificationSvc.SimulateNewNotificationAsync();

                var newer = await NotificationSvc.GetNotificationsSinceAsync(lastSeenId);
                if (newer.Count > 0)
                {
                    notifications.InsertRange(0, newer);
                    lastSeenId = newer.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        _persistSub.Dispose();

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

